        },
        {
          "id": "no_subject_line_echo",
          "label": "Opening doesn't read as a restatement of the subject line"
        }
      ],
      "priority": 2
    },
    {
      "name": "Operational Closings",
      "category": "Structure",
      "description": "The email should land on concrete next steps, deadlines, and accountability \u2014 not dissolve into gratitude or motivation. The reader should walk away knowing exactly what happens next.",
