        {
          "id": "closes_on_action",
          "label": "Final section ends on specific actions, dates, or owners \u2014 not sentiment or thanks"
        },
        {
          "id": "escalation_explicit",
          "label": "Escalation path or point of contact is stated explicitly, not left implied"
        },
        {
          "id": "no_trailing_filler",
          "label": "No motivational filler or gratitude padding appears after the operational close"
        },
