        {
          "id": "no_stock_phrases",
          "label": "Avoids boilerplate phrases like 'I wanted to reach out,' 'thank you for your flexibility,' or 'please don't hesitate'"
        },
        {
          "id": "plain_specific_language",
          "label": "Uses concrete, plain language rather than abstract or padded corporate vocabulary"
