          "label": "Ownership is consolidated to a single person or channel rather than scattered across roles"
        },
        {
          "id": "every_detail_earns_place",
          "label": "Every piece of supporting detail either clarifies the next step or is cut"
        }
      ],
      "priority": 5
    }
